#!/usr/bin/env python3
"""Network Sniffer — Raw socket packet capture with full protocol dissection"""
import socket
import struct
import sys
import time
import signal
import collections

class PacketSniffer:
    ETHERTYPES = {0x0800: 'IPv4', 0x0806: 'ARP', 0x86DD: 'IPv6', 0x8100: 'VLAN'}
    IP_PROTOS = {1: 'ICMP', 6: 'TCP', 17: 'UDP', 47: 'GRE', 50: 'ESP', 51: 'AH'}
    TCP_FLAGS = {0x01: 'FIN', 0x02: 'SYN', 0x04: 'RST', 0x08: 'PSH', 0x10: 'ACK', 0x12: 'SYN-ACK', 0x18: 'PSH-ACK'}

    def __init__(self, interface=None, bpf_filter=None, count=0, timeout=None):
        self.interface = interface
        self.count = count
        self.timeout = timeout
        self.captured = 0
        self.stats = collections.Counter()
        self.running = True
        signal.signal(signal.SIGINT, self._handle_signal)

    def _handle_signal(self, sig, frame):
        self.running = False

    def create_raw_socket(self):
        try:
            sock = socket.socket(socket.AF_PACKET, socket.SOCK_RAW, socket.ntohs(0x0003))
            if self.interface:
                sock.bind((self.interface, 0))
            sock.settimeout(1.0)
            return sock
        except (AttributeError, OSError):
            sock = socket.socket(socket.AF_INET, socket.SOCK_RAW, socket.IPPROTO_IP)
            sock.setsockopt(socket.IPPROTO_IP, socket.IP_HDRINCL, 1)
            try:
                sock.bind(('0.0.0.0', 0))
                sock.ioctl(socket.SIO_RCVALL, socket.RCVALL_ON)
            except (AttributeError, OSError):
                pass
            sock.settimeout(1.0)
            return sock

    def parse_ethernet(self, data):
        if len(data) < 14:
            return None
        dst, src, proto = struct.unpack('!6s6s H', data[:14])
        dst_mac = ':'.join(f'{b:02x}' for b in dst)
        src_mac = ':'.join(f'{b:02x}' for b in src)
        return {'dst_mac': dst_mac, 'src_mac': src_mac, 'ethertype': proto,
                'ethertype_name': self.ETHERTYPES.get(proto, f'0x{proto:04x}'), 'payload': data[14:]}

    def parse_ipv4(self, data):
        if len(data) < 20:
            return None
        vhl = data[0]
        ihl = (vhl & 0x0F) * 4
        total_len, ident, flags_frag, ttl, proto, checksum = struct.unpack('!HHHBBH', data[2:12])
        src_ip = socket.inet_ntoa(data[12:16])
        dst_ip = socket.inet_ntoa(data[16:20])
        flags = (flags_frag >> 13) & 0x07
        frag_offset = flags_frag & 0x1FFF
        return {'version': vhl >> 4, 'ihl': ihl, 'total_len': total_len, 'id': ident,
                'flags': flags, 'frag_offset': frag_offset, 'ttl': ttl, 'protocol': proto,
                'protocol_name': self.IP_PROTOS.get(proto, str(proto)), 'checksum': checksum,
                'src_ip': src_ip, 'dst_ip': dst_ip, 'payload': data[ihl:]}

    def parse_tcp(self, data):
        if len(data) < 20:
            return None
        src_port, dst_port, seq, ack, offset_flags = struct.unpack('!HHIIH', data[:14])
        data_offset = (offset_flags >> 12) * 4
        flags = offset_flags & 0x3F
        window = struct.unpack('!H', data[14:16])[0]
        flag_names = []
        for bit, name in self.TCP_FLAGS.items():
            if flags & bit == bit:
                flag_names.append(name)
        return {'src_port': src_port, 'dst_port': dst_port, 'seq': seq, 'ack': ack,
                'data_offset': data_offset, 'flags': flags, 'flag_str': '|'.join(flag_names) if flag_names else 'NONE',
                'window': window, 'payload': data[data_offset:]}

    def parse_udp(self, data):
        if len(data) < 8:
            return None
        src_port, dst_port, length, checksum = struct.unpack('!HHHH', data[:8])
        return {'src_port': src_port, 'dst_port': dst_port, 'length': length,
                'checksum': checksum, 'payload': data[8:]}

    def parse_arp(self, data):
        if len(data) < 28:
            return None
        hw_type, proto_type, hw_size, proto_size, opcode = struct.unpack('!HHBBH', data[:8])
        sender_mac = ':'.join(f'{b:02x}' for b in data[8:14])
        sender_ip = socket.inet_ntoa(data[14:18])
        target_mac = ':'.join(f'{b:02x}' for b in data[18:24])
        target_ip = socket.inet_ntoa(data[24:28])
        op_name = {1: 'REQUEST', 2: 'REPLY'}.get(opcode, str(opcode))
        return {'opcode': opcode, 'op_name': op_name, 'sender_mac': sender_mac,
                'sender_ip': sender_ip, 'target_mac': target_mac, 'target_ip': target_ip}

    def parse_icmp(self, data):
        if len(data) < 8:
            return None
        icmp_type, code, checksum, ident, seq = struct.unpack('!BBHHH', data[:8])
        type_names = {0: 'Echo Reply', 3: 'Dest Unreachable', 8: 'Echo Request', 11: 'TTL Exceeded'}
        return {'type': icmp_type, 'type_name': type_names.get(icmp_type, str(icmp_type)),
                'code': code, 'checksum': checksum, 'id': ident, 'seq': seq, 'payload': data[8:]}

    def dissect_packet(self, raw_data):
        result = {'timestamp': time.time(), 'raw_len': len(raw_data)}
        eth = self.parse_ethernet(raw_data)
        if not eth:
            ip = self.parse_ipv4(raw_data)
            if ip:
                eth = {'ethertype': 0x0800, 'ethertype_name': 'IPv4', 'payload': raw_data}
                result['ip'] = ip
            else:
                return result
        else:
            result['ethernet'] = eth
        if eth['ethertype'] == 0x0800:
            ip = self.parse_ipv4(eth['payload'])
            if ip:
                result['ip'] = ip
                if ip['protocol'] == 6:
                    tcp = self.parse_tcp(ip['payload'])
                    if tcp:
                        result['tcp'] = tcp
                        self.stats['TCP'] += 1
                elif ip['protocol'] == 17:
                    udp = self.parse_udp(ip['payload'])
                    if udp:
                        result['udp'] = udp
                        self.stats['UDP'] += 1
                elif ip['protocol'] == 1:
                    icmp = self.parse_icmp(ip['payload'])
                    if icmp:
                        result['icmp'] = icmp
                        self.stats['ICMP'] += 1
        elif eth['ethertype'] == 0x0806:
            arp = self.parse_arp(eth['payload'])
            if arp:
                result['arp'] = arp
                self.stats['ARP'] += 1
        return result

    def format_packet(self, pkt):
        ts = time.strftime('%H:%M:%S', time.localtime(pkt['timestamp']))
        parts = [f'[{ts}] {pkt["raw_len"]}B']
        if 'ip' in pkt:
            ip = pkt['ip']
            parts.append(f'{ip["src_ip"]} -> {ip["dst_ip"]} {ip["protocol_name"]} TTL={ip["ttl"]}')
            if 'tcp' in pkt:
                t = pkt['tcp']
                parts.append(f'TCP {t["src_port"]}->{t["dst_port"]} [{t["flag_str"]}] seq={t["seq"]} win={t["window"]}')
                if t['payload']:
                    preview = t['payload'][:64]
                    ascii_preview = ''.join(chr(b) if 32 <= b < 127 else '.' for b in preview)
                    parts.append(f'  DATA[{len(t["payload"])}]: {ascii_preview}')
            elif 'udp' in pkt:
                u = pkt['udp']
                parts.append(f'UDP {u["src_port"]}->{u["dst_port"]} len={u["length"]}')
            elif 'icmp' in pkt:
                i = pkt['icmp']
                parts.append(f'ICMP {i["type_name"]} id={i["id"]} seq={i["seq"]}')
        elif 'arp' in pkt:
            a = pkt['arp']
            parts.append(f'ARP {a["op_name"]} {a["sender_ip"]}({a["sender_mac"]}) -> {a["target_ip"]}')
        return ' | '.join(parts)

    def capture(self, callback=None):
        sock = self.create_raw_socket()
        start_time = time.time()
        print(f'[*] Sniffing started (interface={self.interface or "all"}, count={self.count or "unlimited"})')
        try:
            while self.running:
                if self.timeout and (time.time() - start_time) >= self.timeout:
                    break
                if self.count and self.captured >= self.count:
                    break
                try:
                    raw_data = sock.recv(65535)
                except socket.timeout:
                    continue
                pkt = self.dissect_packet(raw_data)
                self.captured += 1
                if callback:
                    callback(pkt)
                else:
                    print(self.format_packet(pkt))
        finally:
            sock.close()
            elapsed = time.time() - start_time
            print(f'\n[*] Capture complete: {self.captured} packets in {elapsed:.1f}s')
            print(f'[*] Protocol stats: {dict(self.stats)}')

def demo():
    print('[*] Network Sniffer Demo\n')
    sniffer = PacketSniffer(count=50, timeout=10)
    print('[*] Protocol dissection capabilities:')
    print('  - Ethernet (MAC resolution)')
    print('  - IPv4 (fragmentation, TTL, checksum)')
    print('  - TCP (flags, sequence numbers, window size, payload preview)')
    print('  - UDP (ports, length)')
    print('  - ICMP (type classification)')
    print('  - ARP (request/reply, MAC-IP mapping)')
    print('\n[*] Simulating packet parse on crafted data...')
    tcp_pkt = (b'\x45\x00\x00\x3c\x1c\x46\x40\x00\x40\x06\xb1\xe6'
               b'\xac\x10\x0a\x63\xac\x10\x0a\x0c'
               b'\xc6\xb7\x00\x50\x00\x00\x00\x00\x00\x00\x00\x00'
               b'\xa0\x02\xff\xff\xfe\x30\x00\x00')
    result = sniffer.dissect_packet(tcp_pkt)
    if 'ip' in result:
        print(f'  Src: {result["ip"]["src_ip"]}:{result.get("tcp",{}).get("src_port","")}')
        print(f'  Dst: {result["ip"]["dst_ip"]}:{result.get("tcp",{}).get("dst_port","")}')
        print(f'  Proto: {result["ip"]["protocol_name"]}, TTL: {result["ip"]["ttl"]}')
        if 'tcp' in result:
            print(f'  Flags: {result["tcp"]["flag_str"]}')
    print('\n[*] Demo complete')

if __name__ == '__main__':
    demo()

