import json as _json

class CryptoChannel:
    """XOR-based stream cipher with HMAC authentication (no external deps)"""
    def __init__(self, key):
        self.key = hashlib.sha256(key.encode()).digest()
        self.hmac_key = hashlib.sha256(self.key + b'hmac').digest()

    def encrypt(self, data):
        if isinstance(data, str):
            data = data.encode()
        nonce = os.urandom(16)
        keystream = b''
        for i in range(0, len(data) + 16, 32):
            keystream += hashlib.sha256(self.key + nonce + struct.pack('>I', i // 32)).digest()
        encrypted = bytes(a ^ b for a, b in zip(data, keystream[:len(data)]))
        mac = hmac.new(self.hmac_key, nonce + encrypted, hashlib.sha256).digest()[:16]
        return nonce + encrypted + mac

    def decrypt(self, data):
        nonce, encrypted, mac = data[:16], data[16:-16], data[-16:]
        expected_mac = hmac.new(self.hmac_key, nonce + encrypted, hashlib.sha256).digest()[:16]
        if not hmac.compare_digest(mac, expected_mac):
            raise ValueError('HMAC verification failed')
        keystream = b''
        for i in range(0, len(encrypted) + 16, 32):
            keystream += hashlib.sha256(self.key + nonce + struct.pack('>I', i // 32)).digest()
        return bytes(a ^ b for a, b in zip(encrypted, keystream[:len(encrypted)]))

