#!/usr/bin/env python3
"""Modbus/TCP Scanner — Device discovery, function code probing, register enumeration"""
import socket, struct, sys, time, threading

class ModbusClient:
    def __init__(self, host, port=502, timeout=5, unit_id=1):
        self.host = host
        self.port = port
        self.timeout = timeout
        self.unit_id = unit_id
        self.tid = 0

    def _next_tid(self):
        self.tid = (self.tid + 1) & 0xFFFF
        return self.tid

    def _build_request(self, func_code, data=b""):
        tid = self._next_tid()
        pdu = bytes([func_code]) + data
        mbap = struct.pack(">HHHB", tid, 0, len(pdu) + 1, self.unit_id)
        return mbap + pdu, tid

    def _send_recv(self, func_code, data=b""):
        request, tid = self._build_request(func_code, data)
        try:
            sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            sock.settimeout(self.timeout)
            sock.connect((self.host, self.port))
            sock.send(request)
            response = sock.recv(1024)
            sock.close()
            if len(response) < 9:
                return None
            resp_tid = struct.unpack(">H", response[:2])[0]
            resp_unit = response[6]
            resp_func = response[7]
            if resp_func & 0x80:
                exc_code = response[8] if len(response) > 8 else 0
                return {"error": True, "exception": exc_code, "func": func_code}
            return {"error": False, "func": resp_func, "data": response[9:], "raw": response}
        except (socket.timeout, ConnectionRefusedError, OSError) as e:
            return {"error": True, "exception": -1, "message": str(e)}

    def read_device_id(self):
        mei_data = bytes([0x0E, 0x01, 0x00])
        result = self._send_recv(0x2B, mei_data)
        if result and not result.get("error") and result.get("data"):
            data = result["data"]
            objects = {}
            try:
                offset = 5
                num_objects = data[4] if len(data) > 4 else 0
                for _ in range(num_objects):
                    if offset + 2 > len(data): break
                    obj_id = data[offset]
                    obj_len = data[offset + 1]
                    obj_val = data[offset + 2:offset + 2 + obj_len].decode("utf-8", errors="replace")
                    names = {0: "VendorName", 1: "ProductCode", 2: "MajorMinorRevision"}
                    objects[names.get(obj_id, str(obj_id))] = obj_val
                    offset += 2 + obj_len
            except: pass
            return objects
        return None

    def read_holding_registers(self, start=0, count=10):
        data = struct.pack(">HH", start, count)
        result = self._send_recv(0x03, data)
        if result and not result.get("error") and result.get("data"):
            raw = result["data"]
            byte_count = raw[0] if raw else 0
            registers = []
            for i in range(1, byte_count, 2):
                if i + 1 < len(raw):
                    registers.append(struct.unpack(">H", raw[i:i+2])[0])
            return registers
        return None

    def read_coils(self, start=0, count=16):
        data = struct.pack(">HH", start, count)
        result = self._send_recv(0x01, data)
        if result and not result.get("error") and result.get("data"):
            raw = result["data"]
            coils = []
            for byte_val in raw[1:]:
                for bit in range(8):
                    coils.append(bool(byte_val & (1 << bit)))
            return coils[:count]
        return None

    def probe_function_codes(self):
        supported = []
        fc_names = {1: "Read Coils", 2: "Read Discrete Inputs", 3: "Read Holding Registers",
                    4: "Read Input Registers", 5: "Write Single Coil", 6: "Write Single Register",
                    15: "Write Multiple Coils", 16: "Write Multiple Registers",
                    43: "Read Device Identification"}
        test_fcs = [1, 2, 3, 4, 5, 6, 15, 16, 43]
        for fc in test_fcs:
            if fc in (1, 2): data = struct.pack(">HH", 0, 1)
            elif fc in (3, 4): data = struct.pack(">HH", 0, 1)
            elif fc == 5: data = struct.pack(">HH", 0, 0)
            elif fc == 6: data = struct.pack(">HH", 0, 0)
            elif fc == 43: data = bytes([0x0E, 0x01, 0x00])
            else: data = b""
            result = self._send_recv(fc, data)
            if result and not result.get("error"):
                supported.append((fc, fc_names.get(fc, "Unknown")))
            elif result and result.get("exception") not in (-1, 1):
                supported.append((fc, fc_names.get(fc, "Unknown") + " (restricted)"))
        return supported

class ModbusScanner:
    def __init__(self, targets, port=502, timeout=3, threads=10):
        self.targets = targets
        self.port = port
        self.timeout = timeout
        self.threads = threads
        self.results = {}
        self.lock = threading.Lock()

    def _scan_host(self, host):
        client = ModbusClient(host, self.port, self.timeout)
        result = {"host": host, "port": self.port, "alive": False}
        try:
            sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            sock.settimeout(self.timeout)
            sock.connect((host, self.port))
            sock.close()
            result["alive"] = True
        except: return
        device_id = client.read_device_id()
        if device_id:
            result["device_id"] = device_id
            print("  [+] " + host + " — " + str(device_id))
        else:
            print("  [+] " + host + " — Modbus device (no ID)")
        fcs = client.probe_function_codes()
        result["function_codes"] = fcs
        regs = client.read_holding_registers(0, 10)
        if regs: result["registers_0_9"] = regs
        coils = client.read_coils(0, 16)
        if coils: result["coils_0_15"] = coils
        for uid in range(1, 248):
            if uid == 1: continue
            c = ModbusClient(host, self.port, 1, unit_id=uid)
            r = c.read_holding_registers(0, 1)
            if r is not None:
                result.setdefault("unit_ids", []).append(uid)
                if len(result.get("unit_ids", [])) >= 10: break
        with self.lock:
            self.results[host] = result

    def scan(self):
        print("[*] Modbus Scanner — " + str(len(self.targets)) + " targets, port " + str(self.port))
        from concurrent.futures import ThreadPoolExecutor
        with ThreadPoolExecutor(max_workers=self.threads) as pool:
            pool.map(self._scan_host, self.targets)
        alive = [h for h, r in self.results.items() if r["alive"]]
        print("\n[*] " + str(len(alive)) + "/" + str(len(self.targets)) + " Modbus devices found")
        for host, r in self.results.items():
            if not r["alive"]: continue
            print("  " + host + ":")
            if "device_id" in r:
                for k, v in r["device_id"].items():
                    print("    " + k + ": " + v)
            if "function_codes" in r:
                print("    Function codes: " + ", ".join(str(fc) + "(" + name + ")" for fc, name in r["function_codes"]))
            if "registers_0_9" in r:
                print("    Registers[0:9]: " + str(r["registers_0_9"]))
            if "unit_ids" in r:
                print("    Active unit IDs: " + str(r["unit_ids"]))
        return self.results

def demo():
    print("[*] Modbus/TCP Scanner Demo")
    print("  Protocol: Modbus/TCP (port 502)")
    print("  Probes: Device ID (FC 43), Holding Registers (FC 3), Coils (FC 1)")
    print("  Function code enumeration: FC 1-6, 15, 16, 43")
    print("  Unit ID scanning: 1-247")
    client = ModbusClient("127.0.0.1")
    req, tid = client._build_request(0x03, struct.pack(">HH", 0, 10))
    print("  Sample request (" + str(len(req)) + "B): " + req.hex())
    print("  Demo complete")

if __name__ == "__main__":
    if len(sys.argv) > 1:
        targets = sys.argv[1:]
        scanner = ModbusScanner(targets)
        scanner.scan()
    else:
        demo()

