#!/usr/bin/env python3
"""Network Traffic Analyzer — PCAP-like analysis, protocol stats, anomaly detection"""
import socket, struct, sys, time, collections, os

class TrafficAnalyzer:
    def __init__(self, interface=None, duration=60, bpf=None):
        self.interface = interface
        self.duration = duration
        self.packets = []
        self.connections = collections.defaultdict(lambda: {"packets": 0, "bytes": 0, "first": 0, "last": 0})
        self.dns_queries = []
        self.protocol_stats = collections.Counter()
        self.port_stats = collections.Counter()
        self.ip_stats = collections.Counter()
        self.anomalies = []

    def _parse_ip(self, data):
        if len(data) < 20: return None
        ihl = (data[0] & 0x0F) * 4
        total_len = struct.unpack("!H", data[2:4])[0]
        proto = data[9]
        src = socket.inet_ntoa(data[12:16])
        dst = socket.inet_ntoa(data[16:20])
        return {"ihl": ihl, "total_len": total_len, "proto": proto, "src": src, "dst": dst, "payload": data[ihl:]}

    def _parse_tcp(self, data):
        if len(data) < 20: return None
        sp, dp, seq, ack, off_flags = struct.unpack("!HHIIH", data[:14])
        flags = off_flags & 0x3F
        return {"src_port": sp, "dst_port": dp, "seq": seq, "ack": ack, "flags": flags}

    def _parse_udp(self, data):
        if len(data) < 8: return None
        sp, dp, length = struct.unpack("!HHH", data[:6])
        return {"src_port": sp, "dst_port": dp, "length": length, "payload": data[8:]}

    def _parse_dns(self, data):
        if len(data) < 12: return None
        qd_count = struct.unpack("!H", data[4:6])[0]
        if qd_count == 0: return None
        offset = 12
        labels = []
        while offset < len(data) and data[offset] != 0:
            length = data[offset]
            if length & 0xC0 == 0xC0: break
            labels.append(data[offset+1:offset+1+length].decode("utf-8", errors="replace"))
            offset += 1 + length
        return ".".join(labels) if labels else None

    def capture(self):
        try:
            sock = socket.socket(socket.AF_PACKET, socket.SOCK_RAW, socket.ntohs(0x0003))
            if self.interface: sock.bind((self.interface, 0))
        except (AttributeError, OSError):
            sock = socket.socket(socket.AF_INET, socket.SOCK_RAW, socket.IPPROTO_IP)
            sock.bind(("0.0.0.0", 0))
            try: sock.ioctl(socket.SIO_RCVALL, socket.RCVALL_ON)
            except: pass
        sock.settimeout(1.0)
        start = time.time()
        print("[*] Capturing traffic (" + str(self.duration) + "s)...")
        while time.time() - start < self.duration:
            try:
                raw = sock.recv(65535)
                ts = time.time()
                eth_offset = 14 if len(raw) > 14 and raw[12:14] == b"\x08\x00" else 0
                ip = self._parse_ip(raw[eth_offset:])
                if not ip: continue
                self.ip_stats[ip["src"]] += 1
                proto_name = {6: "TCP", 17: "UDP", 1: "ICMP"}.get(ip["proto"], "OTHER")
                self.protocol_stats[proto_name] += 1
                conn_key = None
                if ip["proto"] == 6:
                    tcp = self._parse_tcp(ip["payload"])
                    if tcp:
                        self.port_stats[tcp["dst_port"]] += 1
                        conn_key = ip["src"] + ":" + str(tcp["src_port"]) + "->" + ip["dst"] + ":" + str(tcp["dst_port"])
                        if tcp["flags"] & 0x02 and not (tcp["flags"] & 0x10):
                            self.anomalies.append({"type": "SYN_SCAN", "src": ip["src"], "dst_port": tcp["dst_port"], "ts": ts})
                elif ip["proto"] == 17:
                    udp = self._parse_udp(ip["payload"])
                    if udp:
                        self.port_stats[udp["dst_port"]] += 1
                        conn_key = ip["src"] + ":" + str(udp["src_port"]) + "->" + ip["dst"] + ":" + str(udp["dst_port"])
                        if udp["dst_port"] == 53 and udp["payload"]:
                            query = self._parse_dns(udp["payload"])
                            if query: self.dns_queries.append({"domain": query, "src": ip["src"], "ts": ts})
                if conn_key:
                    c = self.connections[conn_key]
                    c["packets"] += 1
                    c["bytes"] += ip["total_len"]
                    if c["first"] == 0: c["first"] = ts
                    c["last"] = ts
                self.packets.append({"ts": ts, "src": ip["src"], "dst": ip["dst"], "proto": proto_name, "len": ip["total_len"]})
            except socket.timeout: continue
            except: break
        sock.close()
        print("[*] Captured " + str(len(self.packets)) + " packets")

    def detect_anomalies(self):
        for src, count in self.ip_stats.items():
            if count > len(self.packets) * 0.5:
                self.anomalies.append({"type": "HIGH_VOLUME_SRC", "src": src, "packets": count})
        syn_by_src = collections.Counter(a["src"] for a in self.anomalies if a["type"] == "SYN_SCAN")
        for src, count in syn_by_src.items():
            if count > 10:
                self.anomalies.append({"type": "PORT_SCAN_DETECTED", "src": src, "syn_count": count})

    def report(self):
        self.detect_anomalies()
        print("\n" + "=" * 60)
        print("Traffic Analysis Report")
        print("=" * 60)
        print("Total packets: " + str(len(self.packets)))
        print("Unique connections: " + str(len(self.connections)))
        print("\nProtocol distribution:")
        for proto, count in self.protocol_stats.most_common():
            print("  " + proto + ": " + str(count))
        print("\nTop talkers:")
        for ip, count in self.ip_stats.most_common(10):
            print("  " + ip + ": " + str(count) + " packets")
        print("\nTop ports:")
        for port, count in self.port_stats.most_common(10):
            print("  " + str(port) + ": " + str(count))
        if self.dns_queries:
            print("\nDNS queries (" + str(len(self.dns_queries)) + "):")
            domains = collections.Counter(q["domain"] for q in self.dns_queries)
            for domain, count in domains.most_common(10):
                print("  " + domain + ": " + str(count))
        if self.anomalies:
            print("\nAnomalies (" + str(len(self.anomalies)) + "):")
            for a in self.anomalies[:10]:
                print("  [" + a["type"] + "] " + str(a))

def demo():
    print("[*] Network Traffic Analyzer Demo")
    analyzer = TrafficAnalyzer(duration=5)
    print("  Protocols: TCP, UDP, ICMP")
    print("  Detection: SYN scans, port scans, high-volume sources")
    print("  DNS query logging")
    print("  Connection tracking")
    print("  Demo complete")

if __name__ == "__main__":
    if "--capture" in sys.argv:
        analyzer = TrafficAnalyzer(duration=30)
        analyzer.capture()
        analyzer.report()
    else:
        demo()

